import { CSSResultArray, PropertyValues } from 'lit';

// styles
import { styles } from './styles/index.styles';

// components
import '@maersk-global/mds-components-core-segmented-control-item';

// types
import { McList } from '@maersk-global/mds-components-core-list';
import { IMcList } from '@maersk-global/mds-components-core-list/src/lib/types';

/**
 * Purpose: A segmented control to switch between different views or content sections.
 * Category: Navigation, Content Display, Data Display
 * When to use: When you need to present multiple related options in a compact space.
 * When not to use: For unrelated options or when space is not a concern.
 * Works with components: mc-segmented-control-item, mc-card, mc-modal
 * Alternative component names: Segmented Button Group, Tabbed Navigation
 *
 * @element `mc-segmented-control`
 *
 * @event {CustomEvent<IMcListChangeDetail>} listchange - Emitted when a segmented control item is interacted.
 * @event {CustomEvent<IMcListItemsLoadedDetail>} listitemsloaded - Emitted when the segmented control items are loaded.
 * @event {CustomEvent<IMcListFocusChangeDetail>} focuschange - Emitted when a segmented control item receives focus.
 * @event {Event} scroll - Dispatched when the segmented control group is scrolled.
 *
 * @slot - The default slot where the segmented control items go.
 *
 * @csspart `list` - for changing visuals of the inner list container.
 */
export class McSegmentedControl extends McList implements Omit<IMcList, 'type' | 'orientation'> {
  private isDragging = false;
  private startPos = 0;
  private startScrollPos = 0;

  public static get styles(): CSSResultArray {
    return [super.styles, styles];
  }

  public constructor() {
    super();
    this.type = 'single';
    this.width = 'auto';
    this.disablecircularkeynav = true;
    this.keynavigationtype = 'tab';
    this.disablehandlemousemove = true;
    this.scrollToSelectedValue = true;
    this.scrollSelectedIntoView = true;
    this.orientation = 'horizontal';
  }

  protected firstUpdated(changedProperties: PropertyValues): void {
    super.firstUpdated(changedProperties);

    if (this.list && this.orientation === 'horizontal') {
      this.list.addEventListener('mousedown', this.handleDragStart);
      this.list.addEventListener('mousemove', this.handleDragMove);
      this.list.addEventListener('mouseup', this.handleDragEnd);
      this.list.addEventListener('mouseleave', this.handleDragEnd);

      // Prevent default drag behavior on child elements
      this.list.addEventListener('dragstart', (e) => e.preventDefault());
    }
  }

  private handleDragStart = (e: MouseEvent): void => {
    if (!this.list) return;

    this.isDragging = true;
    this.startPos = e.pageX;
    this.startScrollPos = this.list.scrollLeft;
    this.list.style.cursor = 'grabbing';
    this.list.style.scrollBehavior = 'auto'; // Disable smooth scroll during drag
  };

  private handleDragMove = (e: MouseEvent): void => {
    if (!this.isDragging || !this.list) return;

    e.preventDefault();
    const delta = e.pageX - this.startPos;
    this.list.scrollLeft = this.startScrollPos - delta;
  };

  private handleDragEnd = (): void => {
    if (!this.list) return;

    this.isDragging = false;
    this.list.style.cursor = 'grab';
    this.list.style.scrollBehavior = 'smooth'; // Re-enable smooth scroll
  };
}
customElements.get('mc-segmented-control') || customElements.define('mc-segmented-control', McSegmentedControl);
